#include<bits/stdc++.h>
using namespace std;
const long long mod=20100403;
long long fastpow(long long x,long long y)
{
    long long ans=1;
    while(y)
    {
        if(y%2==1)
        {
            ans=ans*x%mod;
        }
        x=x*x%mod;
        y/=2;
    }
    return ans;
}
long long C(long long n,long long m)
{
    long long ans=1,ny=1;
    for(long long i=1;i<=m;i++)
    {
        ans=ans*(n-i+1)%mod;
        ny=(ny*i)%mod;
    }
    ny=fastpow(ny,mod-2);
    ans=ans*ny%mod;
    return ans;
}
int main()
{
    long long n,m;
    scanf("%lld%lld",&n,&m);
    printf("%lld",((C(n+m,m)-C(n+m,m-1))%mod+mod)%mod);
    return 0;
}
